import{_ as e,o as a,c as l,a7 as r}from"./chunks/framework.C5fSpjcB.js";const p=JSON.parse('{"title":"コラボイベント","description":"","frontmatter":{},"headers":[],"relativePath":"ja/events/collab.md","filePath":"ja/events/collab.md","lastUpdated":1775394001000}'),s={name:"ja/events/collab.md"};function i(n,t,o,d,h,c){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="コラボイベント" tabindex="-1">コラボイベント <a class="header-anchor" href="#コラボイベント" aria-label="Permalink to &quot;コラボイベント&quot;">​</a></h1><p>忘却前夜（Morimens）の他作品コラボレーション情報です。</p><h2 id="沙耶の唄コラボ" tabindex="-1">沙耶の唄コラボ <a class="header-anchor" href="#沙耶の唄コラボ" aria-label="Permalink to &quot;沙耶の唄コラボ&quot;">​</a></h2><p>クトゥルフ神話をテーマとした名作ビジュアルノベル「<strong>沙耶の唄</strong>」（ニトロプラス）とのコラボイベントです。</p><h3 id="コラボ概要" tabindex="-1">コラボ概要 <a class="header-anchor" href="#コラボ概要" aria-label="Permalink to &quot;コラボ概要&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">詳細</th></tr></thead><tbody><tr><td style="text-align:left;">コラボ作品</td><td style="text-align:left;">沙耶の唄（Saya no Uta）</td></tr><tr><td style="text-align:left;">開発元</td><td style="text-align:left;">ニトロプラス（Nitroplus）</td></tr><tr><td style="text-align:left;">コラボ内容</td><td style="text-align:left;">クトゥルフ神話という共通テーマを持つ《沙耶の唄》との跨界コラボレーション。コラボ限定の覚醒体が追加された</td></tr><tr><td style="text-align:left;">入手方法</td><td style="text-align:left;">コラボイベント期間中の限定ガチャ/イベント報酬</td></tr></tbody></table><h3 id="コラボ限定コンテンツ" tabindex="-1">コラボ限定コンテンツ <a class="header-anchor" href="#コラボ限定コンテンツ" aria-label="Permalink to &quot;コラボ限定コンテンツ&quot;">​</a></h3><p>沙耶の唄とのコラボでは、以下の限定コンテンツが実装されました：</p><ul><li><strong>コラボ限定覚醒体</strong> — 沙耶の唄から参戦したコラボキャラクター</li><li><strong>限定ストーリーイベント</strong> — コラボ専用のストーリーシナリオ</li><li><strong>限定報酬</strong> — コラボ期間中のみ入手可能なアイテム・外観</li></ul><p>両作品はクトゥルフ神話（ラヴクラフト作品）をベースとした世界観を共有しており、忘却前夜の「融蝕」と沙耶の唄の「認知の変容」という共通テーマが交差するコラボレーションとなっています。</p><div class="tip custom-block"><p class="custom-block-title">TIP</p><p>コラボイベントは復刻の予定が不明な場合が多いです。開催期間中に限定覚醒体・報酬を確実に入手しましょう。</p></div><div class="warning custom-block"><p class="custom-block-title">WARNING</p><p><span class="server-badge server-jp">JP</span> コラボイベントの開催時期はサーバーによって異なります。CNサーバーで先行開催されたコラボがJPサーバーに来るまでタイムラグがある場合があります。</p></div><h2 id="過去のコラボ一覧" tabindex="-1">過去のコラボ一覧 <a class="header-anchor" href="#過去のコラボ一覧" aria-label="Permalink to &quot;過去のコラボ一覧&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">コラボ作品</th><th style="text-align:left;">ジャンル</th><th style="text-align:left;">共通テーマ</th></tr></thead><tbody><tr><td style="text-align:left;">沙耶の唄（Saya no Uta）</td><td style="text-align:left;">ビジュアルノベル</td><td style="text-align:left;">クトゥルフ神話・認知変容・コズミックホラー</td></tr></tbody></table><h2 id="関連ページ" tabindex="-1">関連ページ <a class="header-anchor" href="#関連ページ" aria-label="Permalink to &quot;関連ページ&quot;">​</a></h2><ul><li><a href="./">イベント情報</a></li><li><a href="./current.html">開催中イベント</a></li><li><a href="./../awakeners/list.html">覚醒体一覧</a></li></ul>',16)])])}const b=e(s,[["render",i]]);export{p as __pageData,b as default};
